import React, { useState, useEffect } from "react";
import { api } from "../api";
import Header from "../components/Header";

export default function Payments() {
  const [duePayments, setDuePayments] = useState([]);
  const [paidPayments, setPaidPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchPayments() {
      try {
        const token = localStorage.getItem("token");
        const res = await api.get("/payments", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setDuePayments(res.data.duePayments);
        setPaidPayments(res.data.paidPayments);
        setError(null);
      } catch (err) {
        setError("Failed to load payments");
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    fetchPayments();
  }, []);

  if (loading) return <div>Loading payments...</div>;
  if (error) return <div style={{ color: "red" }}>{error}</div>;

  return (
    <>
      <Header />
      <div style={{ maxWidth: 600, margin: "auto", padding: 20 }}>
        <h2>Payments Due</h2>
        {duePayments.length === 0 ? (
          <p>No pending payments.</p>
        ) : (
          <ul>
            {duePayments.map((payment) => (
              <li key={payment._id} style={{ marginBottom: 10 }}>
                <div>Name: {payment.name}</div>
                <div>Amount: ₹{payment.amount}</div>
                <div>Date: {new Date(payment.date).toLocaleDateString()}</div>
              </li>
            ))}
          </ul>
        )}

        <h2>Paid Payments</h2>
        {paidPayments.length === 0 ? (
          <p>No paid payments.</p>
        ) : (
          <ul>
            {paidPayments.map((payment) => (
              <li key={payment._id} style={{ marginBottom: 10 }}>
                <div>Name: {payment.name}</div>
                <div>Amount: ₹{payment.amount}</div>
                <div>Date: {new Date(payment.date).toLocaleDateString()}</div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </>
  );
}
